'''use crate::types::{DecideInput, DecideOutput};
use std::f64::consts::PI;

// Helper function for comparison with six significant digits
fn round_to_n_significant_digits(value: f64, n: i32) -> f64 {
    if value == 0.0 {
        return 0.0;
    }
    let d = value.abs().log10().floor();
    let power_of_10 = (n as f64 - d - 1.0).exp10();
    (value * power_of_10).round() / power_of_10
}

/// Compares two f64 numbers with respect to six significant digits.
/// Returns "LT" if A < B, "EQ" if A = B, or "GT" if A > B.
pub fn real_compare(a: f64, b: f64) -> &'static str {
    let a_rounded = round_to_n_significant_digits(a, 6);
    let b_rounded = round_to_n_significant_digits(b, 6);

    if a_rounded == b_rounded {
        "EQ"
    } else if a_rounded < b_rounded {
        "LT"
    } else {
        "GT"
    }
}

/// Calculates the Euclidean distance between two points.
fn distance(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x2 - x1).powi(2) + (y2 - y1).powi(2)).sqrt()
}

/// Calculates the absolute area of a triangle given three points.
fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    0.5 * (x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)).abs()
}

/// Checks if three points can be contained within or on a circle of a given radius.
/// Returns true if points are contained, false otherwise.
fn points_in_circle(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64, radius: f64) -> bool {
    // If radius is negative, no circle can contain points
    if real_compare(radius, 0.0) == "LT" {
        return false;
    }

    // Case 1: All three points coincide
    if real_compare(x1, x2) == "EQ" && real_compare(y1, y2) == "EQ" &&
       real_compare(x1, x3) == "EQ" && real_compare(y1, y3) == "EQ" {
        return true;
    }

    // Case 2: Two points coincide
    let p1_p2_same = real_compare(x1, x2) == "EQ" && real_compare(y1, y2) == "EQ";
    let p1_p3_same = real_compare(x1, x3) == "EQ" && real_compare(y1, y3) == "EQ";
    let p2_p3_same = real_compare(x2, x3) == "EQ" && real_compare(y2, y3) == "EQ";

    if p1_p2_same || p1_p3_same || p2_p3_same {
        let max_dist = distance(x1, y1, x2, y2)
                        .max(distance(x1, y1, x3, y3))
                        .max(distance(x2, y2, x3, y3));
        return real_compare(max_dist, 2.0 * radius) != "GT"; // max_dist <= 2*radius
    }

    // Case 3: Three distinct points
    let d_ab = distance(x1, y1, x2, y2);
    let d_bc = distance(x2, y2, x3, y3);
    let d_ca = distance(x3, y3, x1, y1);

    let area = triangle_area(x1, y1, x2, y2, x3, y3);

    if real_compare(area, 0.0) == "EQ" { // Points are collinear
        let max_dist = d_ab.max(d_bc).max(d_ca);
        return real_compare(max_dist, 2.0 * radius) != "GT"; // max_dist <= 2*radius
    } else { // Points form a triangle
        let circumradius = (d_ab * d_bc * d_ca) / (4.0 * area);
        return real_compare(circumradius, radius) != "GT"; // circumradius <= radius
    }
}

/// Calculates the angle formed by three points (p1, p2, p3) where p2 is the vertex.
/// Returns Some(angle_in_radians) or None if the angle is undefined (vertex coincides with p1 or p3).
fn calculate_angle(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> Option<f64> {
    // If the vertex coincides with either of the other two points, angle is undefined.
    if (real_compare(x1, x2) == "EQ" && real_compare(y1, y2) == "EQ") ||
       (real_compare(x3, x2) == "EQ" && real_compare(y3, y2) == "EQ") {
        return None;
    }

    let v1_x = x1 - x2;
    let v1_y = y1 - y2;
    let v2_x = x3 - x2;
    let v2_y = y3 - y2;

    let dot_product = v1_x * v2_x + v1_y * v2_y;
    let magnitude_v1 = (v1_x.powi(2) + v1_y.powi(2)).sqrt();
    let magnitude_v2 = (v2_x.powi(2) + v2_y.powi(2)).sqrt();

    // Avoid division by zero if magnitude is very small (points are effectively coincident, making angle undefined)
    if real_compare(magnitude_v1, 0.0) == "EQ" || real_compare(magnitude_v2, 0.0) == "EQ" {
        return None;
    }

    let cos_angle = dot_product / (magnitude_v1 * magnitude_v2);

    // Clamp cos_angle to [-1, 1] to avoid NaN from acos due to floating point inaccuracies
    let clamped_cos_angle = cos_angle.max(-1.0).min(1.0);

    Some(clamped_cos_angle.acos())
}

/// Determines the quadrant for a given point (x, y) based on the specification's rules.
fn get_quadrant(x: f64, y: f64) -> usize {
    if real_compare(x, 0.0) == "GT" && real_compare(y, 0.0) == "GT" {
        1 // Quadrant I
    } else if real_compare(x, 0.0) != "GT" && real_compare(y, 0.0) == "GT" {
        2 // Quadrant II
    } else if real_compare(x, 0.0) != "GT" && real_compare(y, 0.0) != "GT" {
        3 // Quadrant III
    } else if real_compare(x, 0.0) == "GT" && real_compare(y, 0.0) != "GT" {
        4 // Quadrant IV
    } else { // Point on an axis or origin, use priority rules
        if real_compare(x, 0.0) == "EQ" { // On Y-axis
            if real_compare(y, 0.0) == "GT" || real_compare(y, 0.0) == "EQ" { 1 } else { 3 }
        } else { // On X-axis (y must be 0)
            if real_compare(x, 0.0) == "GT" || real_compare(x, 0.0) == "EQ" { 1 } else { 2 }
        }
    }
}

// LIC 0: (Corresponds to LIC 1 in spec) There exists at least one set of two consecutive data points
// that are a distance greater than the length, LENGTH1, apart.
fn lic0(input: &DecideInput) -> bool {
    if input.numpoints < 2 || real_compare(input.parameters.length1, 0.0) == "LT" {
        return false;
    }

    for i in 0..(input.numpoints - 1) {
        let dist = distance(input.x[i], input.y[i], input.x[i+1], input.y[i+1]);
        if real_compare(dist, input.parameters.length1) == "GT" {
            return true;
        }
    }
    false
}

// LIC 1: (Corresponds to LIC 2 in spec) There exists at least one set of three consecutive data points
// that cannot all be contained within or on a circle of radius RADIUS1.
fn lic1(input: &DecideInput) -> bool {
    if input.numpoints < 3 || real_compare(input.parameters.radius1, 0.0) == "LT" {
        return false;
    }

    for i in 0..(input.numpoints - 2) {
        if !points_in_circle(input.x[i], input.y[i], input.x[i+1], input.y[i+1], input.x[i+2], input.y[i+2], input.parameters.radius1) {
            return true;
        }
    }
    false
}

// LIC 2: (Corresponds to LIC 3 in spec) There exists at least one set of three consecutive data points
// which form an angle such that: angle < (PI - EPSILON), or angle > (PI + EPSILON)
fn lic2(input: &DecideInput) -> bool {
    if input.numpoints < 3 || real_compare(input.parameters.epsilon, 0.0) == "LT" || real_compare(input.parameters.epsilon, PI) != "LT" {
        return false;
    }

    for i in 0..(input.numpoints - 2) {
        if let Some(angle) = calculate_angle(input.x[i], input.y[i], input.x[i+1], input.y[i+1], input.x[i+2], input.y[i+2]) {
            if real_compare(angle, PI - input.parameters.epsilon) == "LT" ||
               real_compare(angle, PI + input.parameters.epsilon) == "GT" {
                return true;
            }
        }
    }
    false
}

// LIC 3: (Corresponds to LIC 4 in spec) There exists at least one set of three consecutive data points
// that are the vertices of a triangle with area greater than AREA1.
fn lic3(input: &DecideInput) -> bool {
    if input.numpoints < 3 || real_compare(input.parameters.area1, 0.0) == "LT" {
        return false;
    }

    for i in 0..(input.numpoints - 2) {
        let area = triangle_area(input.x[i], input.y[i], input.x[i+1], input.y[i+1], input.x[i+2], input.y[i+2]);
        if real_compare(area, input.parameters.area1) == "GT" {
            return true;
        }
    }
    false
}

// LIC 4: (Corresponds to LIC 5 in spec) There exists at least one set of Q_PTS consecutive data points
// that lie in more than QUADS quadrants.
fn lic4(input: &DecideInput) -> bool {
    let q_pts = input.parameters.q_pts;
    let quads = input.parameters.quads;

    if input.numpoints < q_pts || q_pts < 2 || q_pts > input.numpoints || quads < 1 || quads > 3 {
        return false;
    }

    for i in 0..(input.numpoints - q_pts + 1) {
        let mut encountered_quadrants = [false; 4]; // Quadrants 1, 2, 3, 4
        let mut distinct_quadrants_count = 0;

        for j in 0..q_pts {
            let quadrant_idx = get_quadrant(input.x[i+j], input.y[i+j]) - 1;
            if !encountered_quadrants[quadrant_idx] {
                encountered_quadrants[quadrant_idx] = true;
                distinct_quadrants_count += 1;
            }
        }
        if distinct_quadrants_count > quads {
            return true;
        }
    }
    false
}

// LIC 5: (Corresponds to LIC 6 in spec) There exists at least one set of two consecutive data points,
// (X[i], Y[i]) and (X[j], Y[j]), such that X[j] - X[i] < 0 (where i = j - 1).
fn lic5(input: &DecideInput) -> bool {
    if input.numpoints < 2 {
        return false;
    }

    for i in 0..(input.numpoints - 1) {
        if real_compare(input.x[i+1] - input.x[i], 0.0) == "LT" {
            return true;
        }
    }
    false
}

// LIC 6: (Corresponds to LIC 7 in spec) There exists at least one set of N_PTS consecutive data points
// such that at least one of the points lies a distance greater than DIST from the line joining the first and last of these N_PTS points.
fn lic6(input: &DecideInput) -> bool {
    let n_pts = input.parameters.n_pts;

    if input.numpoints < 3 || n_pts < 3 || n_pts > input.numpoints || real_compare(input.parameters.dist, 0.0) == "LT" {
        return false;
    }

    for i in 0..(input.numpoints - n_pts + 1) {
        let p_first_x = input.x[i];
        let p_first_y = input.y[i];
        let p_last_x = input.x[i + n_pts - 1];
        let p_last_y = input.y[i + n_pts - 1];

        let mut lic_met_for_set = false;

        if real_compare(p_first_x, p_last_x) == "EQ" && real_compare(p_first_y, p_last_y) == "EQ" {
            // First and last points are identical
            for j in 1..(n_pts - 1) { // Check intermediate points
                let current_dist = distance(p_first_x, p_first_y, input.x[i+j], input.y[i+j]);
                if real_compare(current_dist, input.parameters.dist) == "GT" {
                    lic_met_for_set = true;
                    break;
                }
            }
        } else {
            // First and last points are distinct. Calculate distance from line.
            // Line equation: Ax + By + C = 0, where A = y2 - y1, B = x1 - x2, C = x2*y1 - y2*x1
            let a_line = p_last_y - p_first_y;
            let b_line = p_first_x - p_last_x;
            let c_line = p_last_x * p_first_y - p_last_y * p_first_x;
            let denominator = (a_line.powi(2) + b_line.powi(2)).sqrt();

            for j in 1..(n_pts - 1) { // Check intermediate points
                let current_x = input.x[i+j];
                let current_y = input.y[i+j];
                let dist_to_line = (a_line * current_x + b_line * current_y + c_line).abs() / denominator;
                if real_compare(dist_to_line, input.parameters.dist) == "GT" {
                    lic_met_for_set = true;
                    break;
                }
            }
        }
        if lic_met_for_set {
            return true;
        }
    }
    false
}

// LIC 7: (Corresponds to LIC 8 in spec) There exists at least one set of two data points separated by
// exactly K_PTS consecutive intervening points that are a distance greater than the length, LENGTH1, apart.
fn lic7(input: &DecideInput) -> bool {
    let k_pts = input.parameters.k_pts;

    if input.numpoints < 3 || k_pts < 1 || k_pts > (input.numpoints - 2) || real_compare(input.parameters.length1, 0.0) == "LT" {
        return false;
    }

    for i in 0..(input.numpoints - k_pts - 1) {
        let j = i + k_pts + 1;
        let dist = distance(input.x[i], input.y[i], input.x[j], input.y[j]);
        if real_compare(dist, input.parameters.length1) == "GT" {
            return true;
        }
    }
    false
}

// LIC 8: (Corresponds to LIC 9 in spec) There exists at least one set of three data points separated by
// exactly A_PTS and B_PTS consecutive intervening points, respectively, that cannot be contained within
// or on a circle of radius RADIUS1.
fn lic8(input: &DecideInput) -> bool {
    let a_pts = input.parameters.a_pts;
    let b_pts = input.parameters.b_pts;

    if input.numpoints < 5 || a_pts < 1 || b_pts < 1 || (a_pts + b_pts) > (input.numpoints - 3) || real_compare(input.parameters.radius1, 0.0) == "LT" {
        return false;
    }

    for i in 0..(input.numpoints - (a_pts + b_pts) - 2) {
        let p1_idx = i;
        let p2_idx = i + a_pts + 1;
        let p3_idx = i + a_pts + b_pts + 2;

        if !points_in_circle(input.x[p1_idx], input.y[p1_idx], input.x[p2_idx], input.y[p2_idx], input.x[p3_idx], input.y[p3_idx], input.parameters.radius1) {
            return true;
        }
    }
    false
}

// LIC 9: (Corresponds to LIC 10 in spec) There exists at least one set of three data points separated by
// exactly C_PTS and D_PTS consecutive intervening points, respectively, that form an angle such that:
// angle < (PI - EPSILON), or angle > (PI + EPSILON)
fn lic9(input: &DecideInput) -> bool {
    let c_pts = input.parameters.c_pts;
    let d_pts = input.parameters.d_pts;

    if input.numpoints < 5 || c_pts < 1 || d_pts < 1 || (c_pts + d_pts) > (input.numpoints - 3) || real_compare(input.parameters.epsilon, 0.0) == "LT" || real_compare(input.parameters.epsilon, PI) != "LT" {
        return false;
    }

    for i in 0..(input.numpoints - (c_pts + d_pts) - 2) {
        let p1_idx = i;
        let p2_idx = i + c_pts + 1;
        let p3_idx = i + c_pts + d_pts + 2;

        if let Some(angle) = calculate_angle(input.x[p1_idx], input.y[p1_idx], input.x[p2_idx], input.y[p2_idx], input.x[p3_idx], input.y[p3_idx]) {
            if real_compare(angle, PI - input.parameters.epsilon) == "LT" ||
               real_compare(angle, PI + input.parameters.epsilon) == "GT" {
                return true;
            }
        }
    }
    false
}

// LIC 10: (Corresponds to LIC 11 in spec) There exists at least one set of three data points separated by
// exactly E_PTS and F_PTS consecutive intervening points, respectively, that are the vertices of a triangle
// with area greater than AREA1.
fn lic10(input: &DecideInput) -> bool {
    let e_pts = input.parameters.e_pts;
    let f_pts = input.parameters.f_pts;

    if input.numpoints < 5 || e_pts < 1 || f_pts < 1 || (e_pts + f_pts) > (input.numpoints - 3) || real_compare(input.parameters.area1, 0.0) == "LT" {
        return false;
    }

    for i in 0..(input.numpoints - (e_pts + f_pts) - 2) {
        let p1_idx = i;
        let p2_idx = i + e_pts + 1;
        let p3_idx = i + e_pts + f_pts + 2;

        let area = triangle_area(input.x[p1_idx], input.y[p1_idx], input.x[p2_idx], input.y[p2_idx], input.x[p3_idx], input.y[p3_idx]);
        if real_compare(area, input.parameters.area1) == "GT" {
            return true;
        }
    }
    false
}

// LIC 11: (Corresponds to LIC 12 in spec) There exists at least one set of two data points, (X[i], Y[i]) and (X[j], Y[j]),
// separated by exactly G_PTS consecutive intervening points, such that X[j] - X[i] < 0 (where i < j).
fn lic11(input: &DecideInput) -> bool {
    let g_pts = input.parameters.g_pts;

    if input.numpoints < 3 || g_pts < 1 || g_pts > (input.numpoints - 2) {
        return false;
    }

    for i in 0..(input.numpoints - g_pts - 1) {
        let j = i + g_pts + 1;
        if real_compare(input.x[j] - input.x[i], 0.0) == "LT" {
            return true;
        }
    }
    false
}

// LIC 12: (Corresponds to LIC 13 in spec) There exists at least one set of two data points, separated by
// exactly K_PTS consecutive intervening points, which are a distance greater than the length, LENGTH1, apart.
// In addition, there exists at least one set of two data points (which can be the same or different from the two data points
// just mentioned), separated by exactly K_PTS consecutive intervening points, that are a distance less than the length, LENGTH2, apart.
fn lic12(input: &DecideInput) -> bool {
    let k_pts = input.parameters.k_pts;

    if input.numpoints < 3 || k_pts < 1 || k_pts > (input.numpoints - 2) || real_compare(input.parameters.length1, 0.0) == "LT" || real_compare(input.parameters.length2, 0.0) == "LT" {
        return false;
    }

    let mut condition1_met = false;
    for i in 0..(input.numpoints - k_pts - 1) {
        let j = i + k_pts + 1;
        let dist = distance(input.x[i], input.y[i], input.x[j], input.y[j]);
        if real_compare(dist, input.parameters.length1) == "GT" {
            condition1_met = true;
            break;
        }
    }

    let mut condition2_met = false;
    for i in 0..(input.numpoints - k_pts - 1) {
        let j = i + k_pts + 1;
        let dist = distance(input.x[i], input.y[i], input.x[j], input.y[j]);
        if real_compare(dist, input.parameters.length2) == "LT" {
            condition2_met = true;
            break;
        }
    }

    condition1_met && condition2_met
}

// LIC 13: (Corresponds to LIC 14 in spec) There exists at least one set of three data points, separated by
// exactly A_PTS and B_PTS consecutive intervening points, respectively, that cannot be contained within
// or on a circle of radius RADIUS1. In addition, there exists at least one set of three data points
// (which can be the same or different from the three data points just mentioned) separated by exactly A_PTS
// and B_PTS consecutive intervening points, respectively, that can be contained in or on a circle of radius RADIUS2.
fn lic13(input: &DecideInput) -> bool {
    let a_pts = input.parameters.a_pts;
    let b_pts = input.parameters.b_pts;

    if input.numpoints < 5 || a_pts < 1 || b_pts < 1 || (a_pts + b_pts) > (input.numpoints - 3) || real_compare(input.parameters.radius1, 0.0) == "LT" || real_compare(input.parameters.radius2, 0.0) == "LT" {
        return false;
    }

    let mut condition1_met = false;
    for i in 0..(input.numpoints - (a_pts + b_pts) - 2) {
        let p1_idx = i;
        let p2_idx = i + a_pts + 1;
        let p3_idx = i + a_pts + b_pts + 2;

        if !points_in_circle(input.x[p1_idx], input.y[p1_idx], input.x[p2_idx], input.y[p2_idx], input.x[p3_idx], input.y[p3_idx], input.parameters.radius1) {
            condition1_met = true;
            break;
        }
    }

    let mut condition2_met = false;
    for i in 0..(input.numpoints - (a_pts + b_pts) - 2) {
        let p1_idx = i;
        let p2_idx = i + a_pts + 1;
        let p3_idx = i + a_pts + b_pts + 2;

        if points_in_circle(input.x[p1_idx], input.y[p1_idx], input.x[p2_idx], input.y[p2_idx], input.x[p3_idx], input.y[p3_idx], input.parameters.radius2) {
            condition2_met = true;
            break;
        }
    }

    condition1_met && condition2_met
}

// LIC 14: (Corresponds to LIC 15 in spec) There exists at least one set of three data points, separated by
// exactly E_PTS and F_PTS consecutive intervening points, respectively, that are the vertices of a triangle
// with area greater than AREA1. In addition, there exist three data points (which can be the same or different
// from the three data points just mentioned) separated by exactly E_PTS and F_PTS consecutive intervening points,
// respectively, that are the vertices of a triangle with area less than AREA2.
fn lic14(input: &DecideInput) -> bool {
    let e_pts = input.parameters.e_pts;
    let f_pts = input.parameters.f_pts;

    if input.numpoints < 5 || e_pts < 1 || f_pts < 1 || (e_pts + f_pts) > (input.numpoints - 3) || real_compare(input.parameters.area1, 0.0) == "LT" || real_compare(input.parameters.area2, 0.0) == "LT" {
        return false;
    }

    let mut condition1_met = false;
    for i in 0..(input.numpoints - (e_pts + f_pts) - 2) {
        let p1_idx = i;
        let p2_idx = i + e_pts + 1;
        let p3_idx = i + e_pts + f_pts + 2;

        let area = triangle_area(input.x[p1_idx], input.y[p1_idx], input.x[p2_idx], input.y[p2_idx], input.x[p3_idx], input.y[p3_idx]);
        if real_compare(area, input.parameters.area1) == "GT" {
            condition1_met = true;
            break;
        }
    }

    let mut condition2_met = false;
    for i in 0..(input.numpoints - (e_pts + f_pts) - 2) {
        let p1_idx = i;
        let p2_idx = i + e_pts + 1;
        let p3_idx = i + e_pts + f_pts + 2;

        let area = triangle_area(input.x[p1_idx], input.y[p1_idx], input.x[p2_idx], input.y[p2_idx], input.x[p3_idx], input.y[p3_idx]);
        if real_compare(area, input.parameters.area2) == "LT" {
            condition2_met = true;
            break;
        }
    }

    condition1_met && condition2_met
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let mut cmv: Vec<bool> = vec![false; 15];

    cmv[0] = lic0(input);
    cmv[1] = lic1(input);
    cmv[2] = lic2(input);
    cmv[3] = lic3(input);
    cmv[4] = lic4(input);
    cmv[5] = lic5(input);
    cmv[6] = lic6(input);
    cmv[7] = lic7(input);
    cmv[8] = lic8(input);
    cmv[9] = lic9(input);
    cmv[10] = lic10(input);
    cmv[11] = lic11(input);
    cmv[12] = lic12(input);
    cmv[13] = lic13(input);
    cmv[14] = lic14(input);

    let mut pum: Vec<Vec<bool>> = vec![vec![false; 15]; 15];
